1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const FIRST_INSURANCE_MULTIPLIER = 1.1;
6	const CURSED_MULTIPLIER = 1.5;
7	const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
8	const LOYALTY_MULTIPLIER = 0.8;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const ADMIN_FEE = 5;
11	
12	// Three alike pieces of a "building-block" item (rune, moonstone, …) pool
13	// to a single unit priced at this fixed tier, irrespective of the per-piece
14	// BASE_PRICE. The tier coincidentally equals amulet's base price today but
15	// is conceptually a separate pricing rule from the per-item ladder.
16	const BUILDING_BLOCK_PRICE = 60;
17	
18	const BASE_PRICE: Record<string, number> = {
19	  sword: 100,
20	  staff: 80,
21	  amulet: 60,
22	  potion: 40,
23	  rune: 25,
24	};
25	
26	function itemModifierMultiplier(item: Item): number {
27	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
28	  const highEnchantment =
29	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
30	  return cursed * highEnchantment;
31	}
32	
33	// MHPCO always rounds the euro value of a discounted/loaded price upward
34	// (in the office's favour). The toFixed(10) step strips IEEE-754 drift so
35	// values that are mathematically integer (e.g. 100 × 1.10 = 110) don't get
36	// bumped up a euro by a 110.00000000000001 representation.
37	function ceilInMhpcoFavor(value: number): number {
38	  return Math.ceil(Number(value.toFixed(10)));
39	}
40	
41	export function runScenario(scenario: unknown): unknown {
42	  const { customer, steps } = scenario as Scenario;
43	  const items = steps[0].items;
44	  const runeCount = items.filter((i) => i.type === "rune").length;
45	  const buildingBlocks = Math.floor(runeCount / 3);
46	  const looseRunes = runeCount % 3;
47	  let itemsTotal = 0;
48	  for (const item of items) {
49	    if (item.type === "rune") continue;
50	    itemsTotal += BASE_PRICE[item.type] * itemModifierMultiplier(item);
51	  }
52	  itemsTotal += buildingBlocks * BUILDING_BLOCK_PRICE + looseRunes * BASE_PRICE["rune"];
53	  const loyaltyMultiplier =
54	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_MULTIPLIER : 1;
55	  const premium =
56	    ceilInMhpcoFavor(itemsTotal * loyaltyMultiplier * FIRST_INSURANCE_MULTIPLIER) +
57	    ADMIN_FEE;
58	  return { results: [{ premium }] };
59	}
